   392→var setCmd = &cobra.Command{
   393→	Use:   "set <name> <temp|keep>",
   394→	Short: "Toggle sandbox between temporary and kept",
   395→	Long: `Toggle a sandbox between temporary (auto-remove on exit) and kept.
   396→
   397→  temp   Mark as temporary — will be removed when the CLI session exits
   398→  keep   Mark as kept — will not be auto-removed`,
   399→	Args: cobra.ExactArgs(2),
   400→	RunE: func(cmd *cobra.Command, args []string) error {
   401→		client, err := api.NewClient()
   402→		if err != nil {
   403→			return err
   404→		}
   405→		printServer(client)
   406→
   407→		sandbox, err := findSandboxByName(client, args[0])
   408→		if err != nil {
   409→			return err
   410→		}
   411→
   412→		mode := strings.ToLower(args[1])
   413→		var temp bool
   414→		switch mode {
   415→		case "temp":
   416→			temp = true
   417→		case "keep":
   418→			temp = false
   419→		default:
   420→			return fmt.Errorf("unknown mode %q: use \"temp\" or \"keep\"", args[1])
   421→		}
   422→
   423→		sandbox, err = client.UpdateSandbox(sandbox.ID, api.UpdateSandboxRequest{Temporary: &temp})
   424→		if err != nil {
   425→			return err
   426→		}
   427→
   428→		if temp {
   429→			fmt.Printf("Sandbox %q set to temporary (will be removed on exit).\n", sandbox.Name)
   430→		} else {
   431→			fmt.Printf("Sandbox %q set to keep (will not be removed on exit).\n", sandbox.Name)
   432→		}
   433→		return nil
   434→	},
   435→}
   436→
   437→func envTruthy(key string) bool {
   438→	v := strings.ToLower(os.Getenv(key))
   439→	return v == "1" || v == "true" || v == "yes"
   440→}
   441→
   442→func findSandboxByName(client *api.Client, name string) (*api.Sandbox, error) {
   443→	sandboxes, err := client.ListSandboxes()
   444→	if err != nil {
   445→		return nil, err
   446→	}
   447→	for _, s := range sandboxes {
   448→		if s.Name == name {
   449→			return &s, nil
   450→		}
   451→	}
   452→	return nil, fmt.Errorf("sandbox %q not found", name)
   453→}
