			sandboxHome = true
		}
		if !cmd.Flags().Changed("rm") && envTruthy("SANDCASTLE_RM") {
			sandboxRemove = true
		}
		if !cmd.Flags().Changed("data") {
			if v := os.Getenv("SANDCASTLE_DATA"); v != "" {
				if v == "1" || v == "true" {
